it('should not produce duplicate items across pages', () => {
  const allItems = Array.from({ length: 10 }, (_, i) => i + 1);
  const page1 = paginate(allItems, 1, 3);
  const page2 = paginate(allItems, 2, 3);
  const page3 = paginate(allItems, 3, 3);
  const page4 = paginate(allItems, 4, 3);

  expect(page1.items).toEqual([1, 2, 3]);
  expect(page2.items).toEqual([4, 5, 6]);
  expect(page3.items).toEqual([7, 8, 9]);
  expect(page4.items).toEqual([10]);

  // Ensure no duplicates across all pages
  const combined = [...page1.items, ...page2.items, ...page3.items, ...page4.items];
  expect(combined).toEqual(allItems);
});

